function setLang(l){
  document.querySelectorAll('.lang-btn').forEach(function(b){b.classList.remove('active')});
  document.querySelectorAll('.lang-btn[onclick="setLang(\''+l+'\')"]').forEach(function(b){b.classList.add('active')});
  document.body.className='lang-'+l;
  var t=i18n[l];
  document.querySelectorAll('[data-i]').forEach(function(el){
    var k=el.getAttribute('data-i');
    if(t[k]!==undefined)el.innerHTML=t[k];
  });
  applyFormTranslations(l);
}

function applyFormTranslations(l){
  var formI18n={
    en:{namePh:'John Smith',emailPh:'hello@company.com',servicePh:'Select a service...',msgPh:'Tell us about your project...',services:['Paid Ads','Branding','Web Design','SEO','Strategy','Analytics']},
    ru:{namePh:'Ваше имя',emailPh:'Email',servicePh:'Выберите услугу...',msgPh:'Расскажите о вашем проекте...',services:['Реклама','Брендинг','Веб-дизайн','SEO','Стратегия','Аналитика']},
    ge:{namePh:'თქვენი სახელი',emailPh:'Email',servicePh:'აირჩიეთ სერვისი...',msgPh:'გვიამბეთ თქვენი პროექტის შესახებ...',services:['რეკლამა','ბრენდინგი','ვებ-დიზაინი','SEO','სტრატეგია','ანალიტიკა']},
    ua:{namePh:'Ваше імʼя',emailPh:'Email',servicePh:'Оберіть послугу...',msgPh:'Розкажіть про ваш проєкт...',services:['Реклама','Брендинг','Веб-дизайн','SEO','Стратегія','Аналітика']}
  };
  var f=formI18n[l]||formI18n.en;
  var nameInput=document.querySelector('input[name="name"], input[placeholder="John Smith"]');
  var emailInput=document.querySelector('input[name="email"], input[placeholder="hello@company.com"]');
  var msgInput=document.querySelector('textarea[name="message"], textarea[placeholder*="project"]');
  var serviceSelect=document.querySelector('select[name="service"]');
  if(nameInput)nameInput.placeholder=f.namePh;
  if(emailInput)emailInput.placeholder=f.emailPh;
  if(msgInput)msgInput.placeholder=f.msgPh;
  if(serviceSelect&&serviceSelect.options.length){
    serviceSelect.options[0].text=f.servicePh;
    for(var i=0;i<f.services.length;i++){
      if(serviceSelect.options[i+1])serviceSelect.options[i+1].text=f.services[i];
    }
  }
}

